	if s.Len() != 2 {
		t.Fatalf("expected 2 after delete, got %d", s.Len())
	}
}

func TestStateStore_Keys(t *testing.T) {
	s := NewStateStore("n1")
	s.Put("c", []byte("3"))
	s.Put("a", []byte("1"))
	s.Put("b", []byte("2"))
	keys := s.Keys()
	if len(keys) != 3 || keys[0] != "a" || keys[1] != "b" || keys[2] != "c" {
