	}

	stddev := func(replicas int) float64 {
		r := NewRing(replicas)
		r.Add("a")
		r.Add("b")
		r.Add("c")
		dist := r.Distribution(keys)
		mean := float64(len(keys)) / 3.0
		var sumSq float64
		for _, c := range dist {
