	hlc := NewHybridLogicalClock("n1").WithPhysicalClock(func() int64 { return 1000 })
	hlc.Tick("n1")
	ts1 := hlc.Now().(*HLCTimestamp)
	ts2 := hlc.Now().(*HLCTimestamp)
	if ts1.WallTime != ts2.WallTime || ts1.Logical != ts2.Logical {
