package gossip

import "testing"

// Verifies that repeated Hash calls are stable until a mutation occurs
func TestStateStore_Hash_CachingBehavior(t *testing.T) {
    s := NewStateStore("n1")
    s.Put("a", []byte("1"))
    s.Put("b", []byte("2"))

    h1 := s.Hash()
    h2 := s.Hash()
    if h1 != h2 {
        t.Fatal("hash should be stable across repeated calls")
    }

    // Put should change the hash
    s.Put("c", []byte("3"))
    h3 := s.Hash()
    if h3 == h2 {
        t.Fatal("hash should change after Put")
    }

    // Apply should change the hash when it applies newer versions
    applied := s.Apply([]*StateEntry{{Key: "d", Value: []byte("4"), Version: 999, NodeID: "remote"}})
    if applied == 0 {
        t.Fatal("expected Apply to apply at least one entry")
    }
    h4 := s.Hash()
    if h4 == h3 {
        t.Fatal("hash should change after Apply")
    }

    // Delete should change the hash
    s.Delete("a")
    h5 := s.Hash()
    if h5 == h4 {
        t.Fatal("hash should change after Delete")
    }
}

