/testbed/frontiercode-repo/pkg/hash/ring.content:
package hash

import "testing"

// Ensure TransferKeys has no side effects on the ring structure.
func TestRing_TransferKeys_NoSideEffects(t *testing.T) {
    r := NewRing(50)
    r.Add("n1")
    r.Add("n2")

    keys := []string{"a", "b", "c", "d", "e"}

    sizeBefore := r.Size()
    vnodesBefore := r.VirtualNodeCount()
    membersBefore := r.Members()

    // Capture a lookup for stability verification
    beforeOwner := r.Lookup("probe-key")

    transfers := r.TransferKeys("n3", keys)
    // Should produce a valid mapping (not asserting volume here)
    if transfers == nil {
        t.Fatal("expected non-nil transfers map")
    }

    // Ring should be unchanged
    if r.Size() != sizeBefore {
        t.Fatalf("ring size changed: before=%d after=%d", sizeBefore, r.Size())
    }
    if r.VirtualNodeCount() != vnodesBefore {
        t.Fatalf("virtual node count changed: before=%d after=%d", vnodesBefore, r.VirtualNodeCount())
    }
    if r.HasNode("n3") {
        t.Fatal("probed node should not be permanently added to the ring")
    }

    // Members list should match exactly
    afterMembers := r.Members()
    if len(afterMembers) != len(membersBefore) {
        t.Fatalf("members length changed: before=%d after=%d", len(membersBefore), len(afterMembers))
    }
    for i := range membersBefore {
        if membersBefore[i] != afterMembers[i] {
            t.Fatalf("members changed: before=%v after=%v", membersBefore, afterMembers)
        }
    }

    // Lookups should be unaffected by TransferKeys side-effect
    if r.Lookup("probe-key") != beforeOwner {
        t.Fatal("lookup result changed after TransferKeys; ring should be unchanged")
    }
}

