package clock

import "testing"

// Benchmark intended to be run with -benchmem to observe zero allocations/op.
func BenchmarkVectorTimestamp_Compare_NoAllocs(b *testing.B) {
    a := NewVectorTimestamp()
    bvt := NewVectorTimestamp()
    for i := 0; i < 100; i++ {
        key := string('a' + rune(i%26)) + string('A'+rune((i/26)%26))
        a.Set(key, uint64(i))
        bvt.Set(key, uint64(i))
    }
    b.ReportAllocs()
    b.ResetTimer()
    for i := 0; i < b.N; i++ {
        if a.Compare(bvt) != Equal {
            b.Fatal("unexpected compare result")
        }
    }
}
